var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_QM","text":{"KOREA":"좀더…… 완전한…… 존재가…….","JPN":"より……完全な……存在に……","ENG":"I must become... more... complete...","TWN":"更加……完美的……存在……"},"stage":{"bg":"HALL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"완전한 존재는 무슨.","JPN":"完全な存在？","ENG":"Complete, my foot.","TWN":"什麼完美的存在。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"침식체 주제에…….","JPN":"侵食体のくせに……","ENG":"You're just another C.O...","TWN":"區區侵蝕體……"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"후…… 일단 살았으니 다행이다…….","JPN":"ふう……とりあえず生き抜いた……","ENG":"Phew... Well, at least I survived...","TWN":"呼……至少我們還活著……"},"stage":{"bg":"MANSION_NIGHT","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"고마워. 카타리나. 덕분에 살았어.","JPN":"ありがとう、カタリナ。おかげで助かったよ。","ENG":"Thanks, Katharina. I owe you one.","TWN":"謝謝你，卡特莉娜。多虧了你。"},"stage":{"bg":"MANSION_NIGHT","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"넷?! 흐, 흠……. 당연하죠! 전 약속은 지킨다고요!","JPN":"はいっ！？　ご、ごほん……当たり前です！　私は約束は必ず守るんです！","ENG":"W-what?! H-hmph... Of course! I always keep my promises!","TWN":"嗯？！哼，哼……當然了！我可是會遵守約定的！"},"stage":{"bg":"MANSION_NIGHT","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"구해줬다고 수고비 같은 건 줄 생각 없으니까 얌전히…….","JPN":"助けてくれたからって報酬とかは期待しないでよね。大人しく……","ENG":"Just so we're clear, I'm not giving you a reward or anything, so–","TWN":"雖然救了我，但別指望有什麼酬勞，老實點……"},"stage":{"bg":"MANSION_NIGHT","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"우왁! 이게 뭐 하는 짓이야?","JPN":"うわっ！　何するんだよ！？","ENG":"Whoa! What do you think you're you doing?!","TWN":"嗚哇！你在幹什麼？"},"stage":{"bg":"MANSION_NIGHT","slots":{"L":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"흐으읍…… 달콤한 냄새…… 참을 수가 없어……!","JPN":"スゥゥ……甘い匂い……たまらない……！","ENG":"*Sniff* You smell so sweet... I can't resist...!","TWN":"呼……甜蜜的氣味……忍不住了……！"},"stage":{"bg":"MANSION_NIGHT","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"이성을 붙잡는 게 너무 힘들어요.","JPN":"理性が……今にも飛んじゃいそうなんです……！","ENG":"It's so hard to hold myself back.","TWN":"保持理智太難了。"},"stage":{"bg":"MANSION_NIGHT","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"한 번만 더 당신 피를 먹으면 안 될까요?","JPN":"もう1回だけ、血を吸わせてくれませんか？","ENG":"Can I just have one more taste of your blood?","TWN":"能再讓我喝一次你的血嗎？"},"stage":{"bg":"MANSION_NIGHT","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"맛만 보고 물러날게요!","JPN":"味見だけしますから！","ENG":"Just a little taste! I'll stop right after!","TWN":"我只嚐一口就好！"},"stage":{"bg":"MANSION_NIGHT","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"사실…… 당신 피 맛을 보고 싶어서 온 거라고요!","JPN":"実は……あなたの血が飲みたくて来たんです！","ENG":"To be honest... I only came back because I wanted to taste your blood again!","TWN":"其實……我是因為想要你的血才回來的！"},"stage":{"bg":"MANSION_NIGHT","slots":{"L":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"하, 한 번만요!","JPN":"い、1回だけでいいです！","ENG":"J-just once, please?","TWN":"一次就好！"},"stage":{"bg":"MANSION_NIGHT","slots":{"L":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"……봤죠, 언니?","JPN":"……見ましたよね、姉さん？","ENG":"...You see this, Agnes?","TWN":"……看到了吧，姊姊？"},"stage":{"bg":"MANSION_NIGHT","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"얘 보면 내가 돈 밝히는 건 약과에요.","JPN":"この子に比べたら私のお金への執着なんて大したことないです。","ENG":"Compared to her, my greed is nothing.","TWN":"看她就知道我愛錢只是小巫見大巫。"},"stage":{"bg":"MANSION_NIGHT","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"후훗, 재밌는 애네.","JPN":"ふふっ、面白い子ね。","ENG":"Haha, she's amusing.","TWN":"呵呵，有趣的傢伙。"},"stage":{"bg":"MANSION_NIGHT","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"감염자들끼리 공명하는 기운 같은 게 있는 걸까?","JPN":"感染者同士、共鳴する何かがあるのかしら？","ENG":"I wonder if there's some kind of resonance between the afflicted...","TWN":"感染者之間是否存在共鳴的氣息？"},"stage":{"bg":"MANSION_NIGHT","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"흥미로운걸?","JPN":"興味深いわ。","ENG":"Doesn't that sound interesting?","TWN":"真是有趣呢？"},"stage":{"bg":"MANSION_NIGHT","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그냥 에그타르트 냄새가 몸에 밴 걸지도…….","JPN":"単純にエッグタルトの匂いが染み付いているだけかも……","ENG":"Or maybe I just smell like egg tarts.","TWN":"可能只是蛋撻的味道沾到身上了……"},"stage":{"bg":"MANSION_NIGHT","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"크흠……! 실례했습니다.","JPN":"こほん……！　失礼しました。","ENG":"Ahem...! Excuse me.","TWN":"咳咳……! 真是失禮了。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"지금도 침 질질 흘리고 있잖아.","JPN":"今も涎ダラダラ垂れてるけど。","ENG":"You're still drooling, you know.","TWN":"現在還在流口水呢。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"함께 위험을 헤쳐 나갔다는 것이 중요하죠.","JPN":"共に危機を乗り越えたという点が重要なんです。","ENG":"What matters is that we overcame danger together!","TWN":"重要的是我們一起克服了危險。"},"stage":{"bg":"CITY_CENTER2","slots":{"L":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};